125→// StartSubscriptions registers all NATS subscriptions for Job and Node APIs.
126→// Messages are delivered to buffered channels and processed by worker goroutines.
127→// Returns an error if the NATS client is not available or subscription fails.
128→func (api *NatsAPI) StartSubscriptions() error {
129→	client := nats.GetClient()
130→	if client == nil {
131→		cclog.Warn("NATS client not available, skipping API subscriptions")
132→		return nil
133→	}
134→
135→	if config.Keys.APISubjects != nil {
136→		s := config.Keys.APISubjects
137→
138→		if err := client.Subscribe(s.SubjectJobEvent, func(subject string, data []byte) {
139→			api.jobCh <- natsMessage{subject: subject, data: data}
140→		}); err != nil {
141→			return err
142→		}
143→
144→		if err := client.Subscribe(s.SubjectNodeState, func(subject string, data []byte) {
145→			api.nodeCh <- natsMessage{subject: subject, data: data}
146→		}); err != nil {
147→			return err
148→		}
149→
150→		cclog.Info("NATS API subscriptions started")
151→	}
152→	return nil
153→}
154→
155→// processJobEvent routes job event messages to the appropriate handler based on the "function" tag.
156→// Validates that required tags and fields are present before processing.
157→func (api *NatsAPI) processJobEvent(msg lp.CCMessage) {
158→	function, ok := msg.GetTag("function")
159→	if !ok {
160→		cclog.Errorf("Job event is missing required tag 'function': measurement=%s", msg.Name())
161→		return
162→	}
163→
164→	switch function {
165→	case "start_job":
166→		v, ok := msg.GetEventValue()
167→		if !ok {
168→			cclog.Errorf("Job start event is missing event field with JSON payload")
169→			return
170→		}
171→		api.handleStartJob(v)
172→
173→	case "stop_job":
174→		v, ok := msg.GetEventValue()
175→		if !ok {
176→			cclog.Errorf("Job stop event is missing event field with JSON payload")
177→			return
178→		}
179→		api.handleStopJob(v)
180→
181→	default:
182→		cclog.Warnf("Unknown job event function '%s', expected 'start_job' or 'stop_job'", function)
183→	}
184→}
185→
186→// handleJobEvent processes job-related messages received via NATS using InfluxDB line protocol.
187→// The message must be in line protocol format with measurement="job" and include:
188→//   - tag "function" with value "start_job" or "stop_job"
189→//   - field "event" containing JSON payload (schema.Job or StopJobAPIRequest)
190→//
191→// Example: job,function=start_job event="{\"jobId\":1001,...}" 1234567890000000000
192→func (api *NatsAPI) handleJobEvent(subject string, data []byte) {
193→	if len(data) == 0 {
194→		cclog.Warnf("NATS %s: received empty message", subject)
195→		return
196→	}
197→
198→	d := influx.NewDecoderWithBytes(data)
199→
200→	for d.Next() {
201→		m, err := receivers.DecodeInfluxMessage(d)
202→		if err != nil {
203→			cclog.Errorf("NATS %s: failed to decode InfluxDB line protocol message: %v", subject, err)
204→			return
205→		}
206→
207→		if !m.IsEvent() {
208→			cclog.Debugf("NATS %s: received non-event message, skipping", subject)
209→			continue
210→		}
211→
212→		if m.Name() == "job" {
213→			api.processJobEvent(m)
214→		} else {
215→			cclog.Debugf("NATS %s: unexpected measurement name '%s', expected 'job'", subject, m.Name())
216→		}
217→	}
218→}
219→
220→// handleStartJob processes job start messages received via NATS.
221→// The payload parameter contains JSON following the schema.Job structure.
222→// Jobs are validated, checked for duplicates, and inserted into the database.
223→func (api *NatsAPI) handleStartJob(payload string) {
224→	if payload == "" {
225→		cclog.Error("NATS start job: payload is empty")
226→		return
227→	}
228→	req := schema.Job{
229→		Shared:           "none",
230→		MonitoringStatus: schema.MonitoringStatusRunningOrArchiving,
231→	}
232→
233→	dec := json.NewDecoder(strings.NewReader(payload))
234→	dec.DisallowUnknownFields()
235→	if err := dec.Decode(&req); err != nil {
236→		cclog.Errorf("NATS start job: parsing request failed: %v", err)
237→		return
238→	}
239→
240→	cclog.Debugf("NATS start job: %s", req.GoString())
241→	req.State = schema.JobStateRunning
242→
243→	if err := importer.SanityChecks(&req); err != nil {
244→		cclog.Errorf("NATS start job: sanity check failed: %v", err)
245→		return
246→	}
247→
248→	var unlockOnce sync.Once
249→	api.RepositoryMutex.Lock()
250→	defer unlockOnce.Do(api.RepositoryMutex.Unlock)
251→
252→	jobs, err := api.JobRepository.FindAll(&req.JobID, &req.Cluster, nil)
253→	if err != nil && err != sql.ErrNoRows {
254→		cclog.Errorf("NATS start job: checking for duplicate failed: %v", err)
255→		return
256→	}
257→	if err == nil {
258→		for _, job := range jobs {
259→			if (req.StartTime - job.StartTime) < secondsPerDay {
260→				cclog.Errorf("NATS start job: job with jobId %d, cluster %s already exists (dbid: %d)",
261→					req.JobID, req.Cluster, job.ID)
262→				return
263→			}
264→		}
265→	}
266→
267→	// When tags are present, insert directly into the job table so that the
268→	// returned ID can be used with AddTagOrCreate (which queries the job table).
269→	var id int64
270→	if len(req.Tags) > 0 {
271→		id, err = api.JobRepository.StartDirect(&req)
272→	} else {
273→		id, err = api.JobRepository.Start(&req)
274→	}
275→	if err != nil {
276→		cclog.Errorf("NATS start job: insert into database failed: %v", err)
277→		return
278→	}
279→	unlockOnce.Do(api.RepositoryMutex.Unlock)
280→
281→	for _, tag := range req.Tags {
282→		if _, err := api.JobRepository.AddTagOrCreate(nil, id, tag.Type, tag.Name, tag.Scope); err != nil {
283→			cclog.Errorf("NATS start job: adding tag to new job %d failed: %v", id, err)
284→			return
285→		}
286→	}
287→
288→	cclog.Infof("NATS: new job (id: %d): cluster=%s, jobId=%d, user=%s, startTime=%d",
289→		id, req.Cluster, req.JobID, req.User, req.StartTime)
290→}
291→
292→// handleStopJob processes job stop messages received via NATS.
293→// The payload parameter contains JSON following the StopJobAPIRequest structure.
294→// The job is marked as stopped in the database and archiving is triggered if monitoring is enabled.
295→func (api *NatsAPI) handleStopJob(payload string) {
296→	if payload == "" {
297→		cclog.Error("NATS stop job: payload is empty")
298→		return
299→	}
300→	var req StopJobAPIRequest
301→
302→	dec := json.NewDecoder(strings.NewReader(payload))
303→	dec.DisallowUnknownFields()
304→	if err := dec.Decode(&req); err != nil {
305→		cclog.Errorf("NATS job stop: parsing request failed: %v", err)
306→		return
307→	}
308→
309→	if req.JobID == nil {
310→		cclog.Errorf("NATS job stop: the field 'jobId' is required")
311→		return
312→	}
313→
314→	isCached := false
315→	job, err := api.JobRepository.FindCached(req.JobID, req.Cluster, req.StartTime)
316→	if err != nil {
317→		// Not in cache, try main job table
318→		job, err = api.JobRepository.Find(req.JobID, req.Cluster, req.StartTime)
319→		if err != nil {
320→			cclog.Errorf("NATS job stop: finding job failed: %v", err)
321→			return
322→		}
323→	} else {
324→		isCached = true
325→	}
326→
327→	if job.State != schema.JobStateRunning {
328→		cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: job has already been stopped (state is: %s)",
329→			job.JobID, job.ID, job.Cluster, job.State)
330→		return
331→	}
332→
333→	if job.StartTime > req.StopTime {
334→		cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: stopTime %d must be >= startTime %d",
335→			job.JobID, job.ID, job.Cluster, req.StopTime, job.StartTime)
336→		return
337→	}
338→
339→	if req.State != "" && !req.State.Valid() {
340→		cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: invalid job state: %#v",
341→			job.JobID, job.ID, job.Cluster, req.State)
342→		return
343→	} else if req.State == "" {
344→		req.State = schema.JobStateCompleted
345→	}
346→
347→	job.Duration = int32(req.StopTime - job.StartTime)
348→	job.State = req.State
349→	api.JobRepository.Mutex.Lock()
350→	defer api.JobRepository.Mutex.Unlock()
351→
352→	// If the job is still in job_cache, transfer it to the job table first
353→	if isCached {
354→		newID, err := api.JobRepository.TransferCachedJobToMain(*job.ID)
355→		if err != nil {
356→			cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: transferring cached job failed: %v",
357→				job.JobID, *job.ID, job.Cluster, err)
358→			return
359→		}
360→		cclog.Infof("NATS: transferred cached job to main table: old id %d -> new id %d (jobId=%d)", *job.ID, newID, job.JobID)
361→		job.ID = &newID
362→	}
363→
364→	if err := api.JobRepository.Stop(*job.ID, job.Duration, job.State, job.MonitoringStatus); err != nil {
365→		cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: marking job as '%s' failed: %v",
366→			job.JobID, *job.ID, job.Cluster, job.State, err)
367→		return
368→	}
369→
370→	cclog.Infof("NATS: archiving job (dbid: %d): cluster=%s, jobId=%d, user=%s, startTime=%d, duration=%d, state=%s",
371→		*job.ID, job.Cluster, job.JobID, job.User, job.StartTime, job.Duration, job.State)
372→
373→	if job.MonitoringStatus == schema.MonitoringStatusDisabled {
374→		return
375→	}
376→
377→	archiver.TriggerArchiving(job)
378→}
379→
380→// processNodestateEvent extracts and processes node state data from the InfluxDB message.
381→// Updates node states in the repository for all nodes in the payload.
382→func (api *NatsAPI) processNodestateEvent(msg lp.CCMessage) {
383→	v, ok := msg.GetEventValue()
384→	if !ok {
385→		cclog.Errorf("Nodestate event is missing event field with JSON payload")
386→		return
387→	}
388→
389→	var req UpdateNodeStatesRequest
390→
391→	dec := json.NewDecoder(strings.NewReader(v))
392→	dec.DisallowUnknownFields()
393→	if err := dec.Decode(&req); err != nil {
394→		cclog.Errorf("NATS nodestate: parsing request failed: %v", err)
395→		return
396→	}
397→
398→	repo := repository.GetNodeRepository()
399→	requestReceived := time.Now().Unix()
400→
401→	updates := make([]repository.NodeStateUpdate, 0, len(req.Nodes))
402→	for _, node := range req.Nodes {
403→		state := determineState(node.States)
404→		nodeState := schema.NodeStateDB{
405→			TimeStamp:       requestReceived,
406→			NodeState:       state,
407→			CpusAllocated:   node.CpusAllocated,
408→			MemoryAllocated: node.MemoryAllocated,
409→			GpusAllocated:   node.GpusAllocated,
410→			HealthState:     schema.MonitoringStateFull,
411→			JobsRunning:     node.JobsRunning,
412→		}
413→		updates = append(updates, repository.NodeStateUpdate{
414→			Hostname:  node.Hostname,
415→			Cluster:   req.Cluster,
416→			NodeState: &nodeState,
417→		})
418→	}
419→
420→	if err := repo.BatchUpdateNodeStates(updates); err != nil {
421→		cclog.Errorf("NATS nodestate: batch update for cluster %s failed: %v", req.Cluster, err)
422→	}
423→
424→	cclog.Debugf("NATS nodestate: updated %d node states for cluster %s", len(req.Nodes), req.Cluster)
425→}
426→
427→// handleNodeState processes node state update messages received via NATS using InfluxDB line protocol.
428→// The message must be in line protocol format with measurement="nodestate" and include:
429→//   - field "event" containing JSON payload (UpdateNodeStatesRequest)
430→//
431→// Example: nodestate event="{\"cluster\":\"testcluster\",\"nodes\":[...]}" 1234567890000000000
432→func (api *NatsAPI) handleNodeState(subject string, data []byte) {
433→	if len(data) == 0 {
434→		cclog.Warnf("NATS %s: received empty message", subject)
435→		return
436→	}
437→
438→	d := influx.NewDecoderWithBytes(data)
439→
440→	for d.Next() {
441→		m, err := receivers.DecodeInfluxMessage(d)
442→		if err != nil {
443→			cclog.Errorf("NATS %s: failed to decode InfluxDB line protocol message: %v", subject, err)
444→			return
445→		}
446→
447→		if !m.IsEvent() {
448→			cclog.Warnf("NATS %s: received non-event message, skipping", subject)
449→			continue
450→		}
451→
452→		if m.Name() == "nodestate" {
453→			api.processNodestateEvent(m)
454→		} else {
455→			cclog.Warnf("NATS %s: unexpected measurement name '%s', expected 'nodestate'", subject, m.Name())
456→		}
457→	}
458→}
