384→// processNodestateEvent extracts and processes node state data from the InfluxDB message.
385→// Updates node states in the repository for all nodes in the payload.
386→func (api *NatsAPI) processNodestateEvent(msg lp.CCMessage) {
387→	v, ok := msg.GetEventValue()
388→	if !ok {
389→		cclog.Errorf("Nodestate event is missing event field with JSON payload")
390→		return
