453→			HealthMetrics:   healthMetrics,
454→			JobsRunning:     node.JobsRunning,
455→		}
456→		updates = append(updates, repository.NodeStateUpdate{
457→			Hostname:  node.Hostname,
458→			Cluster:   req.Cluster,
459→			NodeState: &nodeState,
460→		})
461→	}
462→
463→	if err := repo.BatchUpdateNodeStates(updates); err != nil {
464→		cclog.Errorf("NATS nodestate: batch update for cluster %s failed: %v", req.Cluster, err)
465→	}
466→
467→	cclog.Debugf("NATS nodestate: updated %d node states for cluster %s", len(req.Nodes), req.Cluster)
468→}
469→
470→// handleNodeState processes node state update messages received via NATS using InfluxDB line protocol.
471→// The message must be in line protocol format with measurement="nodestate" and include:
472→//   - field "event" containing JSON payload (UpdateNodeStatesRequest)
473→//
474→// Example: nodestate event="{\"cluster\":\"testcluster\",\"nodes\":[...]}" 1234567890000000000
475→func (api *NatsAPI) handleNodeState(subject string, data []byte) {
476→	if len(data) == 0 {
477→		cclog.Warnf("NATS %s: received empty message", subject)
478→		return
479→	}
480→
481→	d := influx.NewDecoderWithBytes(data)
482→
483→	for d.Next() {
484→		m, err := receivers.DecodeInfluxMessage(d)
485→		if err != nil {
486→			cclog.Errorf("NATS %s: failed to decode InfluxDB line protocol message: %v", subject, err)
487→			return
488→		}
489→
490→		if !m.IsEvent() {
491→			cclog.Warnf("NATS %s: received non-event message, skipping", subject)
492→			continue
493→		}
494→
495→		if m.Name() == "nodestate" {
496→			api.processNodestateEvent(m)
497→		} else {
498→			cclog.Warnf("NATS %s: unexpected measurement name '%s', expected 'nodestate'", subject, m.Name())
499→		}
500→	}
501→}
